import { NextResponse } from "next/server"

// In a real application, you'd use process.env.OPENWEATHER_API_KEY
// and fetch real data from api.openweathermap.org

export async function GET(request: Request) {
  const { searchParams } = new URL(request.url)
  const lat = searchParams.get('lat') || '14.6819'  // default Anantapur, AP
  const lon = searchParams.get('lon') || '77.6006'

  // Simulate network delay
  await new Promise((resolve) => setTimeout(resolve, 500))

  const mockForecast = [
    { day: 0, date: "Today", rain: 0, temp: 32, humidity: 45, riskLevel: "Low" },
    { day: 1, date: "Tomorrow", rain: 0, temp: 33, humidity: 42, riskLevel: "Low" },
    { day: 2, date: "Wednesday", rain: 30, temp: 31, humidity: 65, riskLevel: "Medium" },
    { day: 3, date: "Thursday", rain: 85, temp: 28, humidity: 88, riskLevel: "High", warning: "Heavy Rain Expected" },
    { day: 4, date: "Friday", rain: 20, temp: 30, humidity: 70, riskLevel: "Medium" },
    { day: 5, date: "Saturday", rain: 0, temp: 32, humidity: 50, riskLevel: "Low" },
    { day: 6, date: "Sunday", rain: 0, temp: 33, humidity: 48, riskLevel: "Low" },
  ]

  const recommendedActions = [
    "Harvest mature groundnut immediately before Thursday's heavy rain.",
    "Delay any planned pesticide spraying until Friday.",
    "Ensure drainage channels are clear by Wednesday evening."
  ]

  return NextResponse.json({
    location: "Anantapur, Andhra Pradesh",
    crop: "Groundnut",
    stage: "Maturation",
    forecast: mockForecast,
    actions: recommendedActions
  })
}

"use client"

import * as React from "react"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Badge } from "@/components/ui/badge"
import { CloudRain, AlertTriangle, Droplets, ArrowRight } from "lucide-react"

type ForecastDay = {
  day: number,
  date: string,
  rain: number, // mm or percentage probability
  temp: number,
  humidity: number,
  riskLevel: "Low" | "Medium" | "High",
  warning?: string
}

type WeatherData = {
  location: string,
  crop: string,
  stage: string,
  forecast: ForecastDay[],
  actions: string[]
}

export function RainRiskCard() {
  const [data, setData] = React.useState<WeatherData | null>(null)
  const [loading, setLoading] = React.useState(true)

  React.useEffect(() => {
    async function fetchWeather() {
      try {
        const res = await fetch('/api/weather')
        const json = await res.json()
        setData(json)
      } catch (error) {
        console.error("Failed to fetch weather data", error)
      } finally {
        setLoading(false)
      }
    }
    fetchWeather()
  }, [])

  if (loading || !data) {
    return (
      <Card className="border shadow-sm flex items-center justify-center h-[400px]">
        <div className="animate-pulse flex flex-col items-center">
          <CloudRain className="w-8 h-8 text-muted-foreground mb-4 opacity-50" />
          <p className="text-muted-foreground">Analyzing weather patterns...</p>
        </div>
      </Card>
    )
  }

  return (
    <Card className="border shadow-sm overflow-hidden flex flex-col h-full">
      <CardHeader className="bg-muted/30 border-b pb-4">
        <div className="flex justify-between items-start">
          <div className="space-y-1">
            <CardTitle className="flex items-center gap-2 text-xl">
              <CloudRain className="w-5 h-5 text-blue-500" />
              RainRisk <span className="font-light text-muted-foreground">AI</span>
            </CardTitle>
            <CardDescription className="text-sm">
              Impact analysis for <strong className="text-foreground">{data.crop}</strong> in <strong className="text-foreground">{data.location}</strong>
            </CardDescription>
          </div>
          <Badge variant="outline" className="bg-background">
            <span className="w-1.5 h-1.5 rounded-full bg-blue-500 mr-1.5" />
            Live
          </Badge>
        </div>
      </CardHeader>

      <CardContent className="p-0 flex-1 flex flex-col">
        {/* Timeline */}
        <div className="p-5 border-b">
          <h4 className="text-sm font-medium mb-4 flex items-center justify-between">
            7-Day Risk Timeline
          </h4>
          <div className="flex justify-between gap-1">
            {data.forecast.map((day) => (
              <div key={day.day} className="flex flex-col items-center flex-1 space-y-2">
                <div className="text-xs font-medium text-muted-foreground">{day.date.substring(0, 3)}</div>

                <div 
                  className={`w-full h-12 rounded-sm relative group cursor-pointer transition-transform hover:scale-110 flex items-end justify-center pb-2`}
                  style={{
                    backgroundColor: 
                      day.riskLevel === 'High' ? 'hsl(var(--destructive)/0.2)' : 
                      day.riskLevel === 'Medium' ? '#fef08a' : 
                      '#bbf7d0', // green-200
                  }}
                >
                  {/* Rain representation bar inside the container */}
                  <div 
                    className="absolute bottom-0 w-full rounded-sm opacity-50"
                    style={{ 
                      height: `${Math.min(day.rain, 100)}%`,
                      backgroundColor: day.riskLevel === 'High' ? 'hsl(var(--destructive))' : '#3b82f6'
                    }}
                  />

                  {day.riskLevel === 'High' && (
                    <AlertTriangle className="w-4 h-4 text-destructive absolute top-1 z-10" />
                  )}

                  {/* Tooltip on hover mapping to group */}
                  <div className="hidden group-hover:block absolute bottom-14 z-50 bg-popover text-popover-foreground border shadow-lg text-xs p-2 rounded-md w-32 left-1/2 -translate-x-1/2">
                    <p className="font-semibold mb-1 border-b pb-1">{day.date}</p>
                    <p className="flex items-center justify-between">Rain <span className="font-medium">{day.rain}%</span></p>
                    <p className="flex items-center justify-between">Temp <span className="font-medium">{day.temp}°C</span></p>
                    {day.warning && <p className="text-destructive font-bold mt-1 text-[10px] leading-tight">{day.warning}</p>}
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* AI Recommendations */}
        <div className="p-5 bg-blue-50/30 dark:bg-blue-950/10 flex-1">
          <h4 className="text-sm font-semibold mb-3 flex items-center gap-2 text-blue-800 dark:text-blue-300">
            <span className="w-4 h-4 rounded bg-blue-100 flex items-center justify-center text-[10px]">✨</span>
            AI Recommended Actions
          </h4>
          <ul className="space-y-3">
            {data.actions.map((action, idx) => (
              <li key={idx} className="flex gap-3 text-sm">
                <ArrowRight className="w-4 h-4 text-blue-500 shrink-0 mt-0.5" />
                <span className="text-muted-foreground font-medium">{action}</span>
              </li>
            ))}
          </ul>
        </div>
      </CardContent>
    </Card>
  )
}
